struct node { left: node?; right: node?; value: integer; }
query q() {
            val p = node(
                left = node(left = null, right = null, 123),
                456,
                right = node(left = null, right = null, 789)
            );
            val q = node(
                right = node(left = null, right = null, 789),
                456,
                left = node(left = null, right = null, 123)
            );
            return p == q;
        }

